/* Build the complete VIN-write sequence for a module.
   Returns array of {step, description, frame, expectedResponse, expectsSeed?}.
   
   The first 3 steps go in order. After step 3 (request seed), the caller reads
   the seed from the response and passes it to the unlock algorithm to compute
   the key, THEN calls this function again with the computed key, or hands the
   key directly to the step-4 builder. */
function buildVinWriteSequence(moduleSpec, newVin, computedKey){
  const v=validateVIN(newVin);
  if(!v.valid)throw new Error('VIN validation: '+v.error);
  const vinBytes=vinToBytes(newVin.toUpperCase());
  const sessType=moduleSpec.sessionType||0x03;
  const lvl=moduleSpec.securityLevel||1;
  const did=moduleSpec.vinDidKwp||0x90;
  const seq=[
    {step:1,description:'Enter extended diagnostic session',frame:udsStartDiagSession(sessType),expectedResponse:0x50},
    {step:2,description:'Keep-alive: tester present',frame:udsTesterPresent(false),expectedResponse:0x7E},
    {step:3,description:`Request seed (security level ${lvl})`,frame:udsRequestSeed(lvl),expectedResponse:0x67,expectsSeed:true},
    {step:4,description:'Send computed security key',frame:udsSendKey(lvl,computedKey),expectedResponse:0x67},
    {step:5,description:`Write VIN (DID 0x${did.toString(16).padStart(2,'0')})`,frame:udsWriteDataByLocal(did,vinBytes),expectedResponse:0x7B},
  ];
  if(moduleSpec.vinDidOriginalKwp!==undefined){
    seq.push({step:6,description:`Write original VIN (DID 0x${moduleSpec.vinDidOriginalKwp.toString(16).padStart(2,'0')})`,frame:udsWriteDataByLocal(moduleSpec.vinDidOriginalKwp,vinBytes),expectedResponse:0x7B});
  }
  seq.push({step:seq.length+1,description:'ECU hard reset',frame:udsEcuReset(0x01),expectedResponse:0x51});
  return seq;
}

/* Format a Uint8Array as hex string "3b 90 32 43..." */
function framehex(frame){return Array.from(frame).map(b=>b.toString(16).padStart(2,'0')).join(' ');}

/* ==========================================================================
 * BCM DFLASH VIN PATCHER (offline file-level)
 * ==========================================================================
 * Verified byte-for-byte against known-good OG→PATCHED reference dumps:
 *   2018 Trackhawk, 2019 Scat Pack, 2015 Charger SRT.
 * 
 * Structure:
 *   Primary slots: 4 copies, each 32 bytes at stride 32
 *     [17 VIN bytes][CRC-16/CCITT-FALSE big-endian 2 bytes][13 bytes metadata]
 *   Backup slots: 2 copies, each 10 bytes at known offsets
 *     [8-byte VIN tail (positions 10-17)][CRC-16/CCITT-FALSE big-endian 2 bytes]
 * 
 * Primary slot base offset varies by body/year:
 *   2014-2018 LX:   0x1320
 *   2019+ LX/SRT:   0x52B8
 *   Others:         scan dynamically
 * ========================================================================== */

function crc16CcittFalse(data) {
  let crc = 0xFFFF;
  for (let i = 0; i < data.length; i++) {
    crc ^= data[i] << 8;
    for (let j = 0; j < 8; j++) {
      crc = (crc & 0x8000) ? ((crc << 1) ^ 0x1021) & 0xFFFF : (crc << 1) & 0xFFFF;
    }
  }
  return crc;
}

/* Find all primary and backup VIN slots in a BCM DFLASH dump.
 * Returns {primary: [{offset,vin,storedCrc,computedCrc}], backup: [...]}. */
function findBcmVinSlots(data) {
  if (!(data instanceof Uint8Array)) data = new Uint8Array(data);
  
  // Valid VIN char regex: A-HJ-NPR-Z0-9 (exclude I, O, Q)
  const isVinChar = b => {
    if (b >= 0x30 && b <= 0x39) return true;               // 0-9
    if (b === 0x49 || b === 0x4F || b === 0x51) return false; // I, O, Q
    if (b >= 0x41 && b <= 0x5A) return true;               // A-Z (minus above)
    return false;
  };
  const countryOk = b => ('12345WJY'.indexOf(String.fromCharCode(b)) >= 0);
  
  const primary = [];
  const decoder = new TextDecoder('ascii');
  
  // Scan for 17 consecutive valid VIN chars with valid country code
  let i = 0;
  while (i + 17 <= data.length) {
    if (!countryOk(data[i])) { i++; continue; }
    let ok = true;
    for (let j = 1; j < 17; j++) {
      if (!isVinChar(data[i+j])) { ok = false; break; }
    }
    if (!ok) { i++; continue; }
    if (i + 19 > data.length) break;
    
    const vinBytes = data.slice(i, i+17);
    const vin = decoder.decode(vinBytes);
    const storedCrc = (data[i+17] << 8) | data[i+18];
    const computedCrc = crc16CcittFalse(vinBytes);
    // Only include slots where the stored CRC actually matches — this filters
    // out coincidental 17-char-valid sequences that aren't real VIN slots.
    if (storedCrc === computedCrc) {
      primary.push({offset: i, vin, storedCrc, computedCrc, valid: true});
      i += 17;  // step past this VIN so we don't detect overlapping variants
    } else {
      i++;
    }
  }
  
  // Find backup slots: scan for 8-char VIN tails of known VINs
  const backup = [];
  const knownVins = new Set(primary.map(p => p.vin));
  
  for (const fullVin of knownVins) {
    const tailStr = fullVin.slice(9, 17);
    const tailBytes = new TextEncoder().encode(tailStr);
    
    // Search for all occurrences of the tail bytes
    for (let i = 0; i + 8 <= data.length; i++) {
      let match = true;
      for (let j = 0; j < 8; j++) {
        if (data[i+j] !== tailBytes[j]) { match = false; break; }
      }
      if (!match) continue;
      
      // Skip if inside a primary slot
      if (primary.some(p => p.offset <= i && i < p.offset + 17)) continue;
      if (i + 10 > data.length) continue;
      
      const storedCrc = (data[i+8] << 8) | data[i+9];
      const computedCrc = crc16CcittFalse(tailBytes);
      backup.push({offset: i, tail: tailStr, storedCrc, computedCrc, valid: storedCrc === computedCrc});
    }
  }
  
  return {primary, backup};
}

/* Patch a BCM DFLASH dump: write new VIN to all 4 primary + 2 backup slots
 * with correctly computed CRCs. Returns new Uint8Array. */
function patchBcmVin(dump, newVin) {
  if (!(dump instanceof Uint8Array)) dump = new Uint8Array(dump);
  if (newVin.length !== 17) throw new Error('VIN must be 17 chars');
  
  const upper = newVin.toUpperCase();
  const newVinBytes = new TextEncoder().encode(upper);
  const newTailBytes = newVinBytes.slice(9, 17);
  const newVinCrc = crc16CcittFalse(newVinBytes);
  const newTailCrc = crc16CcittFalse(newTailBytes);
  
  const slots = findBcmVinSlots(dump);
  if (slots.primary.length === 0) {
    throw new Error('No VIN slots found — is this a BCM DFLASH dump?');
  }
  
  const out = new Uint8Array(dump);
  for (const s of slots.primary) {
    out.set(newVinBytes, s.offset);
    out[s.offset + 17] = (newVinCrc >> 8) & 0xFF;
    out[s.offset + 18] = newVinCrc & 0xFF;
  }
  for (const s of slots.backup) {
    out.set(newTailBytes, s.offset);
    out[s.offset + 8] = (newTailCrc >> 8) & 0xFF;
    out[s.offset + 9] = newTailCrc & 0xFF;
  }
  
  return {patched: out, slots, newVinCrc, newTailCrc};
}




